import React from 'react';

const Chatbot = () => {
  const chatbotUrl = 'https://cdn.botpress.cloud/webchat/v3.6/shareable.html?configUrl=https://files.bpcontent.cloud/2026/02/19/17/20260219174210-AT0V0QE8.json'; // Replace with your actual chatbot URL

  return (
    <div className="container" style={{ padding: '40px 20px' }}>
      <h1>AI Chatbot</h1>
      <p>Use the chatbot to ask questions, get support, or explore project recommendations.</p>
      <div style={{ marginTop: '20px', minHeight: '80vh', border: '1px solid #ddd', borderRadius: '12px', overflow: 'hidden' }}>
        <iframe
          title="AI Chatbot"
          src={chatbotUrl}
          style={{ width: '100%', height: '100%', minHeight: '700px', border: 'none' }}
        />
      </div>
      <p style={{ marginTop: '20px', color: '#555' }}>
        If the chatbot does not appear, open it directly:&nbsp;
        <a href={chatbotUrl} target="_blank" rel="noreferrer" style={{ color: '#007BFF' }}>
          {chatbotUrl}
        </a>
      </p>
    </div>
  );
};

export default Chatbot;
